sql:
SELECT name 
FROM employees 
ORDER BY age DESC;

SELECT department_name
FROM departments
WHERE budget = (SELECT MAX(budget) FROM departments);

external_knowledge:
- Performance rating > 4.5: Represents above-average performance;
- Average leave days < 3: Indicates minimal time off requests;
- Active employment status: Confirms the employee is currently working;
- Department name: Specifies the division within the organization the employee belongs to.
